// Wire into message sending:
async send(to: string, message: string) {
  const policy = await this.policyService.getAgentPolicy(this.name);
  const filtered = await this.messageFilter.filterOutbound(
    { to, message },
    policy
  );

  if (!filtered) {
    throw new PolicyViolationError('Message violates policy');
  }

  return this.relaycast.send(filtered);
}

// Wire into message receiving:
private async handleInboundMessage(envelope: Envelope) {
  const policy = await this.policyService.getAgentPolicy(this.name);
  const result = await this.messageFilter.filterInbound(envelope, policy);

  if (result.action === 'quarantine') {
    this.emit('quarantined-message', { envelope, reason: result.reason });
    return;
  }

  if (result.redacted) {
    this.emit('message', {
      ...envelope,
      message: result.redactedContent,
      _metadata: { redacted: true, rules: result.appliedRules }
    });
  } else {
    this.emit('message', envelope);
  }
}
```

#### **Phase 4: Policy Configuration**

**1. Workspace Policy Schema** (extend `packages/policy/src/agent-policy.ts`)
```yaml
# ~/.config/agent-relay/policies/message-rules.yaml
name: message-filtering-rules
version: 1.0.0

redactionPolicies:
  strict-redaction:
    rules:
      - category: credential
        patterns:
          - "(?i)(api[_-]?key|token|password)\\s*[:=]\\s*([^\\s]+)"
          - "(?i)authorization:\\s*bearer\\s+([^\\s]+)"
        redactionTemplate: "[REDACTED-CREDENTIAL]"
        severity: high
      - category: pii
        patterns:
          - "\\b\\d{3}-\\d{2}-\\d{4}\\b"  # SSN
          - "\\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}\\b"  # Email
        redactionTemplate: "[REDACTED-PII]"
        severity: medium

messageFilters:
  block-external-messages:
    rules:
      - type: recipient
        pattern: "*@external.com"
        match: glob
    actions: deny

agentRules:
  - name: DataScientist
    sensitivityLevel: confidential
    redactionPolicy: strict-redaction
    filterPolicy: block-external-messages
    messageQuota: 1000  # per hour
    attachmentFilters: ["exe", "dll", "sh"]

  - name: Worker*
    sensitivityLevel: internal
    redactionPolicy: strict-redaction
    messageQuota: 500
```

#### **Phase 5: Audit & Observability**

**1. Filter Audit Log** (`src/filter-audit.rs`)
```rust
pub struct FilterAuditEntry {
  pub timestamp: u64,
  pub sender: String,
  pub recipient: String,
  pub action: FilterAction,
  pub reason: String,
  pub redacted_fields: Vec<String>,
  pub message_id: String,
}

pub enum FilterAction {
  Allowed,
  Redacted(Vec<String>),  // which fields were redacted
  Denied(String),         // reason
  Quarantined(String),    // quarantine reason
}
```

**2. Monitoring Integration** (`packages/telemetry/src/filter-metrics.ts`)
```typescript
export class FilterMetrics {
  recordFilterAction(
    action: FilterAction,
    category: string,
    severity: string
  ): void;

  recordRedaction(
    fieldType: string,
    policyName: string
  ): void;

  getFilterStats(
    timeRange: TimeRange
  ): FilterStatistics;
}
```

### Deployment Zones

| Component | Location | Surface |
|-----------|----------|---------|
| Core policies | `packages/policy/src/message-policy.ts` | Shared SDK + Broker |
| Broker filtering | `src/filter.rs` | Rust broker binary |
| Redaction engine | `src/redact.rs` (enhanced) | Rust broker binary |
| Client-side filter | `packages/sdk/src/message-filter.ts` | TypeScript SDK |
| Audit & telemetry | `packages/telemetry/src/` | Both |

### Integration Checklist

- [ ] Extend `AgentPolicy` with filter/redaction fields
- [ ] Implement `FilterPolicy` and `RedactionPolicy` types
- [ ] Build broker-side `MessageFilter` + `RedactionEngine`
- [ ] Wire filtering into routing layer (`routing.rs`)
- [ ] Build client-side `ClientMessageFilter`
- [ ] Integrate with `RelayClient.send()` and message handler
- [ ] Add policy configuration schema + validation
- [ ] Implement audit logging + metrics
- [ ] Document policy authoring guide
- [ ] Add e2e test coverage (broker + SDK roundtrip)

### Key Design Decisions

1. **Broker Enforcement**: Primary filtering happens at broker level (security boundary)
2. **Client-side Validation**: Pre-flight checks prevent unnecessary roundtrips
3. **Multi-level Policies**: Agent policies + message policies provide flexible control
4. **Graceful Degradation**: Unredacted messages still route if policy allows
5. **Audit Trail**: All filter decisions logged for compliance

